CREATE TABLE `N_HYOSU` (
  `RecordSpec` varchar(2) DEFAULT NULL COMMENT '[COL] name=レコード種別ID; column=RecordSpec; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=H1でレコード形式を識別',
  `DataKubun` varchar(1) DEFAULT NULL COMMENT '[COL] name=データ区分; column=DataKubun; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=2前日売最終/4確定/5確定(月)/9中止/0削除',
  `MakeDate` varchar(8) DEFAULT NULL COMMENT '[COL] name=データ作成年月日; column=MakeDate; table=N_HYOSU; class=蓄積系; unit=yyyymmdd; doc=12-3-06-HYOSU; desc=作成日(西暦8桁)',
  `Year` varchar(4) NOT NULL COMMENT '[COL] name=開催年; column=Year; table=N_HYOSU; class=蓄積系; unit=yyyy; doc=12-3-06-HYOSU; desc=施行年',
  `MonthDay` varchar(4) DEFAULT NULL COMMENT '[COL] name=開催月日; column=MonthDay; table=N_HYOSU; class=蓄積系; unit=mmdd; doc=12-3-06-HYOSU; desc=施行月日',
  `JyoCD` varchar(2) NOT NULL COMMENT '[COL] name=競馬場コード; column=JyoCD; table=N_HYOSU; class=蓄積系; ref=code:2001; doc=12-3-06-HYOSU; desc=施行競馬場コード',
  `Kaiji` varchar(2) NOT NULL COMMENT '[COL] name=開催回; column=Kaiji; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=同年同場の開催回',
  `Nichiji` varchar(2) NOT NULL COMMENT '[COL] name=開催日目; column=Nichiji; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=開催回内の日目',
  `RaceNum` varchar(2) NOT NULL COMMENT '[COL] name=レース番号; column=RaceNum; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=該当レース番号',
  `TorokuTosu` varchar(2) DEFAULT NULL COMMENT '[COL] name=登録頭数; column=TorokuTosu; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=出馬表発表時の登録頭数',
  `SyussoTosu` varchar(2) DEFAULT NULL COMMENT '[COL] name=出走頭数; column=SyussoTosu; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=取消･除外反映後の出走頭数',
  `HatubaiFlag1` varchar(1) DEFAULT NULL COMMENT '[COL] name=発売フラグ(単勝); column=HatubaiFlag1; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=0無/1発売前取消/3発売後取消/7発売あり',
  `HatubaiFlag2` varchar(1) DEFAULT NULL COMMENT '[COL] name=発売フラグ(複勝); column=HatubaiFlag2; table=N_HYOSU; class=蓄積系; doc=12-3-06-HYOSU; desc=0無/1発売前取消/3発売後取消/7発売あり',
