CREATE TABLE `N_MINING` (
  `RecordSpec` varchar(2) DEFAULT NULL COMMENT '[COL] name=レコード種別ID; column=RecordSpec; table=N_MINING; class=蓄積系; doc=12-3-44-MINING; desc=DMでレコード形式を識別',
  `DataKubun` varchar(1) DEFAULT NULL COMMENT '[COL] name=データ区分; column=DataKubun; table=N_MINING; class=蓄積系; doc=12-3-44-MINING; vals=1:前日予想(出馬発表後) 2:当日予想(天候馬場発表後) 3:直前予想(馬体重発表後)',
  `MakeDate` varchar(8) DEFAULT NULL COMMENT '[COL] name=データ作成年月日; column=MakeDate; table=N_MINING; class=蓄積系; unit=yyyymmdd; doc=12-3-44-MINING',
  `Year` varchar(4) NOT NULL COMMENT '[COL] name=開催年; column=Year; table=N_MINING; class=蓄積系; unit=yyyy; key=○; doc=12-3-44-MINING',
  `MonthDay` varchar(4) DEFAULT NULL COMMENT '[COL] name=開催月日; column=MonthDay; table=N_MINING; class=蓄積系; unit=mmdd; key=○; doc=12-3-44-MINING',
  `JyoCD` varchar(2) NOT NULL COMMENT '[COL] name=競馬場コード; column=JyoCD; table=N_MINING; class=蓄積系; ref=code:2001; key=○; doc=12-3-44-MINING',
  `Kaiji` varchar(2) NOT NULL COMMENT '[COL] name=開催回; column=Kaiji; table=N_MINING; class=蓄積系; key=○; doc=12-3-44-MINING; desc=同年同場での第N回',
  `Nichiji` varchar(2) NOT NULL COMMENT '[COL] name=開催日目; column=Nichiji; table=N_MINING; class=蓄積系; key=○; doc=12-3-44-MINING; desc=開催回内のN日目',
  `RaceNum` varchar(2) NOT NULL COMMENT '[COL] name=レース番号; column=RaceNum; table=N_MINING; class=蓄積系; key=○; doc=12-3-44-MINING',
  `MakeHM` varchar(4) DEFAULT NULL COMMENT '[COL] name=データ作成時分; column=MakeHM; table=N_MINING; class=蓄積系; unit=hhmm; doc=12-3-44-MINING; desc=時分各2桁',
  `Umaban1` varchar(2) DEFAULT NULL COMMENT '[COL] name=馬番1; column=Umaban1; table=N_MINING; class=蓄積系; doc=12-3-44-MINING; desc=01～18を設定',
  `DMTime1` varchar(5) DEFAULT NULL COMMENT '[COL] name=予想走破タイム1; column=DMTime1; table=N_MINING; class=蓄積系; doc=12-3-44-MINING; format=9分99秒99',
