  `Corner1` varchar(1) DEFAULT NULL COMMENT '[COL] name=コーナー1; column=Corner1; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1角 2:2角 3:3角 4:4角',
  `Syukaisu1` varchar(1) DEFAULT NULL COMMENT '[COL] name=周回数1; column=Syukaisu1; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1周 2:2周 3:3周',
  `Jyuni1` varchar(70) DEFAULT NULL COMMENT '[COL] name=通過順位1; column=Jyuni1; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=先頭内側からの通過順位(書式あり)',
  `Corner2` varchar(1) DEFAULT NULL COMMENT '[COL] name=コーナー2; column=Corner2; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1角 2:2角 3:3角 4:4角',
  `Syukaisu2` varchar(1) DEFAULT NULL COMMENT '[COL] name=周回数2; column=Syukaisu2; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1周 2:2周 3:3周',
