  `Corner3` varchar(1) DEFAULT NULL COMMENT '[COL] name=コーナー3; column=Corner3; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1角 2:2角 3:3角 4:4角',
  `Syukaisu3` varchar(1) DEFAULT NULL COMMENT '[COL] name=周回数3; column=Syukaisu3; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1周 2:2周 3:3周',
  `Jyuni3` varchar(70) DEFAULT NULL COMMENT '[COL] name=通過順位3; column=Jyuni3; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=先頭内側からの通過順位(書式あり)',
  `Corner4` varchar(1) DEFAULT NULL COMMENT '[COL] name=コーナー4; column=Corner4; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1角 2:2角 3:3角 4:4角',
  `Syukaisu4` varchar(1) DEFAULT NULL COMMENT '[COL] name=周回数4; column=Syukaisu4; table=N_RACE; class=蓄積系; doc=12-3-03-RACE; desc=1:1周 2:2周 3:3周',
