CREATE TABLE `N_RECORD` (
  `RecordSpec` varchar(2) DEFAULT NULL COMMENT '[COL] name=レコード種別ID; column=RecordSpec; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; desc=RCでレコード形式を識別',
  `DataKubun` varchar(1) DEFAULT NULL COMMENT '[COL] name=データ区分; column=DataKubun; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; desc=1初期値/0削除',
  `MakeDate` varchar(8) DEFAULT NULL COMMENT '[COL] name=データ作成年月日; column=MakeDate; table=N_RECORD; class=蓄積系; unit=yyyymmdd; doc=12-3-36-RECORD',
