  `Kaiji` varchar(2) NOT NULL COMMENT '[COL] name=開催回; column=Kaiji; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; key=○; desc=同年同場での第N回',
  `Nichiji` varchar(2) NOT NULL COMMENT '[COL] name=開催日目; column=Nichiji; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; key=○; desc=その開催のN日目',
  `RaceNum` varchar(2) NOT NULL COMMENT '[COL] name=レース番号; column=RaceNum; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; key=○',
  `TokuNum` varchar(4) NOT NULL COMMENT '[COL] name=特別競走番号; column=TokuNum; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; key=GⅠのみ',
  `Hondai` varchar(60) DEFAULT NULL COMMENT '[COL] name=競走名本題; column=Hondai; table=N_RECORD; class=蓄積系; unit=全角30; doc=12-3-36-RECORD',
  `GradeCD` varchar(1) DEFAULT NULL COMMENT '[COL] name=グレードコード; column=GradeCD; table=N_RECORD; class=蓄積系; ref=code:2003; doc=12-3-36-RECORD',
