  `Kyori` varchar(4) NOT NULL COMMENT '[COL] name=距離; column=Kyori; table=N_RECORD; class=蓄積系; unit=m; doc=12-3-36-RECORD; key=○',
  `TrackCD` varchar(2) NOT NULL COMMENT '[COL] name=トラックコード; column=TrackCD; table=N_RECORD; class=蓄積系; ref=code:2009; doc=12-3-36-RECORD; key=○',
  `RecKubun` varchar(1) DEFAULT NULL COMMENT '[COL] name=レコード区分; column=RecKubun; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; desc=1:基準 2:レコード 3:参考 4:備考',
  `RecTime` varchar(4) DEFAULT NULL COMMENT '[COL] name=レコードタイム; column=RecTime; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; format=9分99秒9',
  `TenkoCD` varchar(1) DEFAULT NULL COMMENT '[COL] name=天候コード; column=TenkoCD; table=N_RECORD; class=蓄積系; ref=code:2011; doc=12-3-36-RECORD',
  `SibaBabaCD` varchar(1) DEFAULT NULL COMMENT '[COL] name=芝馬場状態コード; column=SibaBabaCD; table=N_RECORD; class=蓄積系; ref=code:2010; doc=12-3-36-RECORD',
  `DirtBabaCD` varchar(1) DEFAULT NULL COMMENT '[COL] name=ダート馬場状態コード; column=DirtBabaCD; table=N_RECORD; class=蓄積系; ref=code:2010; doc=12-3-36-RECORD',
  `RecUmaKettoNum1` varchar(10) DEFAULT NULL COMMENT '[COL] name=血統登録番号1; column=RecUmaKettoNum1; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; desc=yyyy+品種1+5桁',
  `RecUmaBamei1` varchar(36) DEFAULT NULL COMMENT '[COL] name=馬名1; column=RecUmaBamei1; table=N_RECORD; class=蓄積系; unit=全角18; doc=12-3-36-RECORD',
  `RecUmaUmaKigoCD1` varchar(2) DEFAULT NULL COMMENT '[COL] name=馬記号コード1; column=RecUmaUmaKigoCD1; table=N_RECORD; class=蓄積系; ref=code:2204; doc=12-3-36-RECORD',
  `RecUmaSexCD1` varchar(1) DEFAULT NULL COMMENT '[COL] name=性別コード1; column=RecUmaSexCD1; table=N_RECORD; class=蓄積系; ref=code:2202; doc=12-3-36-RECORD',
  `RecUmaChokyosiCode1` varchar(5) DEFAULT NULL COMMENT '[COL] name=調教師コード1; column=RecUmaChokyosiCode1; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD',
  `RecUmaChokyosiName1` varchar(34) DEFAULT NULL COMMENT '[COL] name=調教師名1; column=RecUmaChokyosiName1; table=N_RECORD; class=蓄積系; unit=全角17; doc=12-3-36-RECORD; desc=姓+全角空白1+名（外国人は連続17）',
  `RecUmaFutan1` varchar(3) DEFAULT NULL COMMENT '[COL] name=負担重量1; column=RecUmaFutan1; table=N_RECORD; class=蓄積系; unit=0.1kg; doc=12-3-36-RECORD',
  `RecUmaKisyuCode1` varchar(5) DEFAULT NULL COMMENT '[COL] name=騎手コード1; column=RecUmaKisyuCode1; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD',
