  `RecUmaUmaKigoCD2` varchar(2) DEFAULT NULL COMMENT '[COL] name=馬記号コード2; column=RecUmaUmaKigoCD2; table=N_RECORD; class=蓄積系; ref=code:2204; doc=12-3-36-RECORD',
  `RecUmaSexCD2` varchar(1) DEFAULT NULL COMMENT '[COL] name=性別コード2; column=RecUmaSexCD2; table=N_RECORD; class=蓄積系; ref=code:2202; doc=12-3-36-RECORD',
  `RecUmaChokyosiCode2` varchar(5) DEFAULT NULL COMMENT '[COL] name=調教師コード2; column=RecUmaChokyosiCode2; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD',
  `RecUmaChokyosiName2` varchar(34) DEFAULT NULL COMMENT '[COL] name=調教師名2; column=RecUmaChokyosiName2; table=N_RECORD; class=蓄積系; unit=全角17; doc=12-3-36-RECORD; desc=姓+全角空白1+名（外国人は連続17）',
  `RecUmaFutan2` varchar(3) DEFAULT NULL COMMENT '[COL] name=負担重量2; column=RecUmaFutan2; table=N_RECORD; class=蓄積系; unit=0.1kg; doc=12-3-36-RECORD',
  `RecUmaKisyuCode2` varchar(5) DEFAULT NULL COMMENT '[COL] name=騎手コード2; column=RecUmaKisyuCode2; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD',
  `RecUmaKisyuName2` varchar(34) DEFAULT NULL COMMENT '[COL] name=騎手名2; column=RecUmaKisyuName2; table=N_RECORD; class=蓄積系; unit=全角17; doc=12-3-36-RECORD; desc=姓+全角空白1+名（外国人は連続17）',
  `RecUmaKettoNum3` varchar(10) DEFAULT NULL COMMENT '[COL] name=血統登録番号3; column=RecUmaKettoNum3; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD; desc=yyyy+品種1+5桁',
  `RecUmaBamei3` varchar(36) DEFAULT NULL COMMENT '[COL] name=馬名3; column=RecUmaBamei3; table=N_RECORD; class=蓄積系; unit=全角18; doc=12-3-36-RECORD',
  `RecUmaUmaKigoCD3` varchar(2) DEFAULT NULL COMMENT '[COL] name=馬記号コード3; column=RecUmaUmaKigoCD3; table=N_RECORD; class=蓄積系; ref=code:2204; doc=12-3-36-RECORD',
  `RecUmaSexCD3` varchar(1) DEFAULT NULL COMMENT '[COL] name=性別コード3; column=RecUmaSexCD3; table=N_RECORD; class=蓄積系; ref=code:2202; doc=12-3-36-RECORD',
  `RecUmaChokyosiCode3` varchar(5) DEFAULT NULL COMMENT '[COL] name=調教師コード3; column=RecUmaChokyosiCode3; table=N_RECORD; class=蓄積系; doc=12-3-36-RECORD',
  `RecUmaChokyosiName3` varchar(34) DEFAULT NULL COMMENT '[COL] name=調教師名3; column=RecUmaChokyosiName3; table=N_RECORD; class=蓄積系; unit=全角17; doc=12-3-36-RECORD; desc=姓+全角空白1+名（外国人は連続17）',
