CREATE TABLE `S_COURSE_CHANGE` (
  `RecordSpec` varchar(2) DEFAULT NULL COMMENT '[COL] name=レコード種別ID; column=RecordSpec; table=S_COURSE_CHANGE; class=速報系; doc=12-3-43-COURSE_CHANGE; desc=CCでレコード形式を識別',
