  `JiyuCD` varchar(1) DEFAULT NULL COMMENT '[COL] name=事由コード; column=JiyuCD; table=S_COURSE_CHANGE; class=速報系; doc=12-3-43-COURSE_CHANGE; vals=1:強風 2:台風 3:雪 4:その他',
