  `Nichiji` varchar(2) NOT NULL COMMENT '[COL] name=開催日目; column=Nichiji; table=S_JODDS_UMAREN_HEAD; class=速報系; key=○; doc=12-3-49-JODDS_UMAREN_HEAD',
