CREATE TABLE `S_MINING` (
  `RecordSpec` varchar(2) DEFAULT NULL COMMENT '[COL] name=レコード種別ID; column=RecordSpec; table=S_MINING; class=速報系; doc=12-3-44-MINING; desc=DMでレコード形式を識別',
  `DataKubun` varchar(1) DEFAULT NULL COMMENT '[COL] name=データ区分; column=DataKubun; table=S_MINING; class=速報系; doc=12-3-44-MINING; vals=1:前日予想(出馬発表後) 2:当日予想(天候馬場発表後) 3:直前予想(馬体重発表後)',
  `MakeDate` varchar(8) DEFAULT NULL COMMENT '[COL] name=データ作成年月日; column=MakeDate; table=S_MINING; class=速報系; unit=yyyymmdd; doc=12-3-44-MINING',
