  `Nichiji` varchar(2) NOT NULL COMMENT '[COL] name=開催日目; column=Nichiji; table=S_MINING; class=速報系; key=○; doc=12-3-44-MINING; desc=開催回内のN日目',
  `RaceNum` varchar(2) NOT NULL COMMENT '[COL] name=レース番号; column=RaceNum; table=S_MINING; class=速報系; key=○; doc=12-3-44-MINING',
  `MakeHM` varchar(4) DEFAULT NULL COMMENT '[COL] name=データ作成時分; column=MakeHM; table=S_MINING; class=速報系; unit=hhmm; doc=12-3-44-MINING; desc=時分各2桁',
  `Umaban1` varchar(2) DEFAULT NULL COMMENT '[COL] name=馬番1; column=Umaban1; table=S_MINING; class=速報系; doc=12-3-44-MINING; desc=01～18を設定',
