  `RecUmaKettoNum2` varchar(10) DEFAULT NULL COMMENT '[COL] name=血統登録番号2; column=RecUmaKettoNum2; table=S_RECORD; class=速報系; doc=12-3-36-RECORD; desc=yyyy+品種1+5桁',
